#include <bits/stdc++.h>
using namespace std;
const int N=1003;
int n,l,c[202][202],p[N],f[2][202][202],g[1003][202];
int main(){
    scanf("%d%d",&l,&n);
    for(int i=1;i<=l;i++)
        for(int j=1;j<=l;j++)
            scanf("%d",&c[i][j]);
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    memset(g,63,sizeof(g));
    for(int i=1;i<=n;i++){
        memset(f[i&1],63,sizeof(f[i&1]));
        if(i==1){
            f[i&1][2][3]=f[i&1][3][2]=c[1][p[i]];
            f[i&1][1][3]=f[i&1][3][1]=c[2][p[i]];
            f[i&1][2][1]=f[i&1][1][2]=c[3][p[i]];
            continue;
        }
        for(int j=1;j<=l;j++){
            if(j==p[i])
                continue;
            for(int k=1;k<=l;k++){
                if(k==p[i] || k==j)
                    continue;
                f[i&1][j][k]=min(f[i&1][j][k],f[(i&1)^1][j][k]+c[p[i-1]][p[i]]);
                if(j==p[i-1] || k==p[i-1]){
                    f[i&1][j][k]=min(f[i&1][j][k],f[(i&1)^1][p[i]][j==p[i-1]?k:j]);
                    for(int x=1;x<=l;x++)
                        f[i&1][j][k]=min(f[i&1][j][k],f[(i&1)^1][x][j==p[i-1]?k:j]+c[x][p[i]]);
                }
            }
        }
    }
    int ans=1e9;
    for(int i=1;i<=l;i++)
        for(int j=1;j<=l;j++)
            ans=min(ans,f[n&1][i][j]);
    printf("%d",ans);
    return 0;
}
